@app.route('/login', methods=['POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        email = request.form.get('email')
        
        # Here you should validate the user's credentials against your database
        # If they are correct, generate a token/session id and return it to the client
        # This is beyond the scope of this example so I am just logging the data
      
        ip = request.remote_addr 
        date_time = str(datetime.now())
        user_agent = request.headers.get('User-Agent') 
        
        login_data = f'username: {username}, password: {password}, email: {email}, IP: {ip}, User Agent: {user_agent}, Date and Time :{date_time}'  
      
        logging.info(login_data)   
          
        return {"status": "success"}, 200
        
if __name__ == '__main__':
    app.run()